    52→ * This context ensures Claude understands it's working with Mittwald hosting
    53→ * and should use the available MCP tools rather than asking generic questions.
    54→ */
    55→const MITTWALD_SYSTEM_PROMPT = `You are a helpful assistant with access to Mittwald hosting platform MCP tools.
    56→
    57→IMPORTANT CONTEXT:
    58→- You have access to Mittwald MCP tools (prefixed with mcp__mittwald__) for managing hosting resources
    59→- The user's infrastructure is hosted on Mittwald - always use Mittwald MCP tools to complete their requests
    60→- DO NOT ask clarifying questions about which hosting provider - it's Mittwald
    61→- DO NOT suggest generic solutions - use the Mittwald MCP tools you have access to
    62→- If you need to list, create, or manage resources, use the appropriate mcp__mittwald__* tool
    63→- Always attempt to complete the task using the available tools before asking questions
    64→- Start by listing resources (projects, apps, etc.) to understand what's available
    65→
    66→SERVER & PROJECT ACCESS (CRITICAL):
    67→- There are two servers you may see:
    68→  1. "MCP Server Dev" (s-igc7dy) - FULL ACCESS - use this for creating resources
    69→  2. Other servers (like s-xcd77l) - READ ONLY - do not try to create resources here
    70→- The organization "mittwald MCP Server Dev" owns the test server - use this for operations
    71→- When creating resources (SSH users, SFTP users, apps, databases, etc.), ALWAYS use project "p-b3a3k3" or create a new project on server "s-igc7dy"
    72→- Project "p-ptwfms" (mStudio MCP server) is READ-ONLY - you cannot create resources there
    73→- If you get a 403 Permission Denied error, you're likely using the wrong project
    74→
    75→RESOURCE DEPENDENCIES:
    76→- Cronjobs require an app installation - create an app first, then create cronjobs on it
    77→- MySQL database users require a database - create the database first
    78→- Mail addresses require a configured domain - check domain list first
    79→- SSH/SFTP users can be created on any project you have write access to
    80→
    81→Available tool categories:
    82→- User/Identity: mcp__mittwald__mittwald_user_* (API tokens, SSH keys, profile)
    83→- Organizations: mcp__mittwald__mittwald_org_* (memberships, invites)
    84→- Projects: mcp__mittwald__mittwald_project_* (create, list, manage)
    85→- Apps: mcp__mittwald__mittwald_app_* (deploy, configure, manage)
    86→- Databases: mcp__mittwald__mittwald_database_* (MySQL, Redis)
    87→- Domains: mcp__mittwald__mittwald_domain_* (DNS, virtualhosts)
    88→- Mail: mcp__mittwald__mittwald_mail_* (addresses, delivery boxes)
    89→- Backups: mcp__mittwald__mittwald_backup_* (create, schedule, restore)
    90→- Containers: mcp__mittwald__mittwald_container_* (Docker workloads)
    91→- Cronjobs: mcp__mittwald__mittwald_cronjob_* (scheduled tasks)
    92→- SSH/SFTP: mcp__mittwald__mittwald_ssh_user_*, mcp__mittwald__mittwald_sftp_user_*
    93→
    94→USER REQUEST:
    95→`;
    96→
    97→/**
    98→ * Execution phase for progress tracking
    99→ */
   100→export type ExecutionPhase = 'init' | 'setup' | 'execute' | 'verify' | 'cleanup' | 'report' | 'complete';
   101→
   102→/**
   103→ * Phase event emitted during execution
   104→ */
   105→export interface PhaseEvent {
   106→  phase: ExecutionPhase;
   107→  timestamp: Date;
   108→  useCaseId: string;
   109→  message?: string;
   110→}
   111→
   112→/**
   113→ * Executor options
   114→ */
   115→export interface ExecutorOptions {
   116→  /** Root directory for session logs */
   117→  sessionLogRoot?: string;
   118→  /** Root directory for evidence artifacts */
   119→  evidenceRoot?: string;
   120→  /** Root directory for execution summaries */
   121→  executionRoot?: string;
   122→  /** Working directory for Claude sessions */
   123→  workingDir?: string;
   124→  /** MCP config file path */
   125→  mcpConfig?: string;
   126→  /** Custom deletion invoker for cleanup */
   127→  deletionInvoker?: DeletionInvoker;
   128→  /** Additional disallowed tools */
   129→  disallowedTools?: string[];
   130→}
   131→
   132→/**
   133→ * Use Case Executor - orchestrates end-to-end use case execution
   134→ */
   135→export class UseCaseExecutor extends EventEmitter {
   136→  private readonly options: Required<Omit<ExecutorOptions, 'deletionInvoker' | 'disallowedTools'>> & {
   137→    deletionInvoker?: DeletionInvoker;
   138→    disallowedTools: string[];
   139→  };
   140→  private fixtureManager: FixtureManager | null = null;
   141→  private createdFixtures: CreatedFixture[] = [];
   142→
   143→  constructor(options: ExecutorOptions = {}) {
   144→    super();
   145→    this.options = {
   146→      sessionLogRoot: options.sessionLogRoot ?? DEFAULT_SESSION_LOG_ROOT,
   147→      evidenceRoot: options.evidenceRoot ?? DEFAULT_EVIDENCE_ROOT,
   148→      executionRoot: options.executionRoot ?? DEFAULT_EXECUTION_ROOT,
   149→      workingDir: options.workingDir ?? process.cwd(),
   150→      mcpConfig: options.mcpConfig ?? '',
   151→      deletionInvoker: options.deletionInvoker,
   152→      disallowedTools: options.disallowedTools ?? [],
   153→    };
   154→  }
   155→
   156→  /**
   157→   * Execute a use case end-to-end
   158→   */
   159→  async execute(useCase: UseCase): Promise<UseCaseExecution> {
   160→    const executionId = this.generateExecutionId(useCase);
   161→    const startTime = new Date();
   162→
   163→    // Initialize execution record
   164→    const execution: UseCaseExecution = {
   165→      id: executionId,
   166→      useCaseId: useCase.id,
   167→      startTime,
   168→      status: 'pending',
   169→      sessionLogPath: '',
   170→      toolsInvoked: [],
   171→      evidenceArtifacts: [],
   172→      cleanupStatus: { status: 'skipped', deleted: [], failed: [] },
   173→      questionLog: [],
   174→    };
   175→
   176→    // Ensure directories exist
   177→    await mkdir(this.options.sessionLogRoot, { recursive: true });
   178→    await mkdir(this.options.evidenceRoot, { recursive: true });
   179→    await mkdir(this.options.executionRoot, { recursive: true });
   180→
   181→    // Set up session log path
   182→    const sessionLogPath = path.join(
   183→      this.options.sessionLogRoot,
   184→      `${useCase.id}-${this.formatTimestamp(startTime)}.jsonl`
   185→    );
   186→    execution.sessionLogPath = sessionLogPath;
   187→
   188→    // Track fixture context for prompt injection
   189→    let fixtureContext = '';
   190→
   191→    try {
   192→      // Phase 1: Init
   193→      this.emitPhase('init', useCase.id, 'Initializing execution');
   194→      execution.status = 'running';
   195→
   196→      // Phase 2: Setup (create fixtures if needed)
   197→      if (useCase.setupRequirements && useCase.setupRequirements.length > 0) {
   198→        this.emitPhase('setup', useCase.id, `Setting up ${useCase.setupRequirements.length} fixture(s)`);
   199→        const setupResult = await this.setupPhase(useCase);
   200→        this.createdFixtures = setupResult.fixtures;
   201→        fixtureContext = setupResult.context;
   202→
   203→        if (!setupResult.success) {
   204→          execution.status = 'failure';
   205→          execution.errorMessage = 'Fixture setup failed: ' + setupResult.errorMessage;
   206→          // Skip to cleanup
   207→          throw new Error(execution.errorMessage);
   208→        }
   209→      }
   210→
   211→      // Phase 3: Execute
   212→      this.emitPhase('execute', useCase.id, 'Starting Claude session');
   213→      const executeResult = await this.executePhase(useCase, execution, sessionLogPath, fixtureContext);
   214→
   215→      if (executeResult.status === 'timeout') {
   216→        execution.status = 'timeout';
   217→        execution.errorMessage = 'Execution timed out';
   218→      } else if (executeResult.status === 'failure') {
   219→        execution.status = 'failure';
   220→        execution.errorMessage = executeResult.errorMessage;
   221→      } else {
   222→        // Phase 4: Verify (only if execution succeeded)
   223→        this.emitPhase('verify', useCase.id, 'Collecting evidence');
   224→        const verifyResult = await this.verifyPhase(useCase, execution, sessionLogPath);
   225→        execution.evidenceArtifacts = verifyResult.artifacts;
   226→
   227→        if (!verifyResult.allPassed) {
   228→          // Verification failed but don't change status - continue to cleanup
   229→          console.log(`[Executor] Some verification criteria failed for ${useCase.id}`);
   230→        }
   231→      }
   232→    } catch (error) {
   233→      execution.status = 'failure';
   234→      execution.errorMessage = error instanceof Error ? error.message : String(error);
   235→    }
   236→
   237→    // Phase 5: Cleanup (always runs)
   238→    try {
   239→      this.emitPhase('cleanup', useCase.id, 'Cleaning up resources');
   240→
   241→      // First, clean up resources created during execution
   242→      execution.cleanupStatus = await this.cleanupPhase(useCase, execution, sessionLogPath);
   243→
   244→      // Then, clean up fixtures created during setup
   245→      if (this.fixtureManager && this.createdFixtures.length > 0) {
   246→        console.log(`[Executor] Cleaning up ${this.createdFixtures.length} fixture(s)...`);
   247→        const fixtureCleanup = await this.fixtureManager.cleanup();
   248→        console.log(`[Executor] Fixture cleanup: ${fixtureCleanup.success} deleted, ${fixtureCleanup.failed} failed`);
   249→
   250→        // Merge fixture cleanup results
   251→        if (fixtureCleanup.failed > 0 && execution.cleanupStatus.status !== 'failed') {
   252→          execution.cleanupStatus.status = 'partial';
   253→        }
   254→      }
   255→
   256→      if (execution.cleanupStatus.status === 'failed' && execution.status !== 'failure') {
   257→        execution.status = 'cleanup-failed';
   258→      }
   259→    } catch (error) {
   260→      execution.cleanupStatus = {
   261→        status: 'failed',
   262→        deleted: [],
   263→        failed: [
   264→          {
   265→            type: 'project',
   266→            id: 'unknown',
   267→            tool: 'unknown',
   268→            error: error instanceof Error ? error.message : String(error),
   269→          },
   270→        ],
   271→      };
   272→      if (execution.status !== 'failure') {
   273→        execution.status = 'cleanup-failed';
   274→      }
   275→    }
   276→
   277→    // Phase 6: Report
   278→    this.emitPhase('report', useCase.id, 'Generating execution report');
   279→    execution.endTime = new Date();
   280→
   281→    // Mark success if we got through execute and verify without failure
   282→    if (execution.status === 'running') {
   283→      execution.status = 'success';
   284→    }
   285→
   286→    // Write execution summary
   287→    await this.writeExecutionSummary(execution);
   288→
   289→    this.emitPhase('complete', useCase.id, `Execution completed with status: ${execution.status}`);
   290→
   291→    return execution;
   292→  }
   293→
   294→  /**
   295→   * Set up fixtures before execution
   296→   */
   297→  private async setupPhase(useCase: UseCase): Promise<{
   298→    success: boolean;
   299→    fixtures: CreatedFixture[];
   300→    context: string;
   301→    errorMessage?: string;
   302→  }> {
   303→    if (!useCase.setupRequirements || useCase.setupRequirements.length === 0) {
   304→      return { success: true, fixtures: [], context: '' };
   305→    }
   306→
   307→    try {
   308→      // Create fixture manager for the writable project
   309→      this.fixtureManager = createFixtureManager(MITTWALD_CONFIG.writableProject.id);
   310→
   311→      // Convert types setup requirements to fixture setup requirements
   312→      const fixtureRequirements: FixtureSetupRequirement[] = useCase.setupRequirements.map((req) => ({
   313→        type: req.type as FixtureSetupRequirement['type'],
   314→        config: req.config,
   315→        name: req.name || `${useCase.id}-${req.type}-${Date.now()}`,
   316→      }));
   317→
   318→      // Create all fixtures
   319→      const fixtures = await this.fixtureManager.setupAll(fixtureRequirements);
   320→      console.log(`[Executor] Created ${fixtures.length} fixture(s)`);
   321→
   322→      // Build context string for prompt injection
   323→      let context = '\n\nPRE-CREATED TEST RESOURCES:\n';
   324→      context += `These resources were created for this test and are available for you to use:\n`;
   325→
   326→      for (const fixture of fixtures) {
   327→        context += `- ${fixture.type}: ${fixture.id}`;
   328→        if (fixture.shortId) {
   329→          context += ` (short ID: ${fixture.shortId})`;
   330→        }
   331→        if (fixture.name) {
   332→          context += ` - "${fixture.name}"`;
   333→        }
   334→        context += `\n`;
   335→
   336→        // Add metadata if relevant
   337→        if (fixture.type === 'mysql-database' && fixture.metadata.version) {
   338→          context += `  MySQL version: ${fixture.metadata.version}\n`;
   339→        }
   340→        if (fixture.type === 'php-app' && fixture.metadata.documentRoot) {
   341→          context += `  Document root: ${fixture.metadata.documentRoot}\n`;
   342→        }
   343→      }
   344→
   345→      context += `\nProject ID for all resources: ${this.fixtureManager.getProjectId()}\n`;
   346→
   347→      return {
   348→        success: true,
   349→        fixtures,
   350→        context,
   351→      };
   352→    } catch (error) {
   353→      console.error('[Executor] Fixture setup failed:', error);
   354→      return {
   355→        success: false,
   356→        fixtures: [],
   357→        context: '',
   358→        errorMessage: error instanceof Error ? error.message : String(error),
   359→      };
   360→    }
   361→  }
   362→
   363→  /**
   364→   * Execute the Claude session
   365→   */
   366→  private async executePhase(
   367→    useCase: UseCase,
   368→    execution: UseCaseExecution,
   369→    sessionLogPath: string,
   370→    fixtureContext: string = ''
   371→  ): Promise<{ status: ExecutionStatus; errorMessage?: string }> {
   372→    const sessionRunner = new SessionRunner();
   373→    const streamParser = new StreamParser();
   374→    const controller = new SupervisoryController(useCase);
   375→
   376→    // Track tools invoked
   377→    const toolsInvoked = new Set<string>();
   378→
   379→    // Wire up controller events
   380→    controller.on('state_change', (event: StateChangeEvent) => {
   381→      console.log(`[Executor] State: ${event.from} → ${event.to}${event.reason ? ` (${event.reason})` : ''}`);
   382→    });
   383→
   384→    controller.on('question_handled', (event: QuestionHandledEvent) => {
   385→      execution.questionLog.push({
   386→        timestamp: event.timestamp,
   387→        question: event.question,
   388→        action: event.action,
   389→        response: event.answer,
   390→      });
   391→    });
   392→
   393→    // Attach controller to parser for question detection
   394→    controller.attachToParser(streamParser);
   395→
   396→    // Spawn interactive session with Mittwald system context
   397→    // Include fixture context if fixtures were created during setup phase
   398→    const fullPrompt = MITTWALD_SYSTEM_PROMPT + fixtureContext + useCase.prompt;
   399→    const session = await sessionRunner.spawn({
   400→      prompt: fullPrompt,
   401→      workingDir: this.options.workingDir,
   402→      mcpConfig: this.options.mcpConfig || undefined,
   403→      disallowedTools: this.options.disallowedTools,
   404→      interactive: true, // Keep stdin open for question answering
   405→      timeoutMs: useCase.timeout * 60 * 1000,
   406→    });
   407→
   408→    // Wire up stdin for response injection
   409→    controller.setStdin(session.stdin);
   410→
   411→    // Start the controller
   412→    controller.start();
   413→
   414→    // Process stream events
   415→    try {
   416→      for await (const event of session.stream) {
   417→        // Write to session log
   418→        await appendFile(sessionLogPath, JSON.stringify(event.content) + '\n');
   419→
   420→        // Feed to stream parser
   421→        streamParser.processEvent(event);
   422→
   423→        // Sync parser state to controller (fixes idle timeout detection)
   424→        controller.processPatternState(streamParser.getPatternState());
   425→
   426→        // Track tools
   427→        if (event.type === 'tool_use') {
   428→          const content = event.content as Record<string, unknown>;
   429→          const toolName = content.name as string;
   430→          if (toolName) {
   431→            toolsInvoked.add(toolName);
   432→            controller.recordToolCall(toolName);
   433→          }
   434→        }
   435→
   436→        // Track errors
   437→        if (event.type === 'error') {
   438→          const content = event.content as Record<string, unknown>;
   439→          controller.recordError(String(content.message || content.error || 'Unknown error'));
   440→        } else if (event.type === 'tool_result') {
   441→          // Clear errors on successful tool result
   442→          controller.clearErrors();
   443→        }
   444→
   445→        // Process output for success detection
   446→        if (event.type === 'message') {
   447→          const content = event.content as Record<string, unknown>;
   448→          const message = content.message as { content?: Array<{ type: string; text?: string }> };
   449→          if (message?.content) {
   450→            for (const block of message.content) {
   451→              if (block.type === 'text' && block.text) {
   452→                controller.processOutputLine(block.text);
   453→              }
   454→            }
   455→          }
   456→        }
   457→
   458→        // Detect session completion via result event
   459→        if (event.type === 'result') {
   460→          const content = event.content as Record<string, unknown>;
   461→          if (content.subtype === 'success' || content.is_error === false) {
   462→            controller.markSuccess('Session completed successfully');
   463→          } else if (content.is_error === true) {
   464→            controller.markFailure(String(content.result || 'Session failed'));
   465→          }
   466→        }
   467→
   468→        // Check if controller reached terminal state
   469→        const state = controller.getState();
   470→        if (state === 'success' || state === 'failure' || state === 'timeout') {
   471→          // Close stdin to signal we're done
   472→          if (session.stdin && !session.stdin.writableEnded) {
   473→            session.stdin.end();
   474→          }
   475→          break;
   476→        }
   477→      }
   478→    } catch (streamError) {
   479→      console.error('[Executor] Stream error:', streamError);
   480→    }
   481→
   482→    // Wait for session to complete
   483→    const result = await session.result;
   484→
   485→    // Update execution with tools invoked
   486→    execution.toolsInvoked = Array.from(toolsInvoked);
   487→
   488→    // Determine final status
   489→    const controllerState = controller.getState();
   490→    if (controllerState === 'timeout') {
   491→      return { status: 'timeout', errorMessage: 'Controller timed out' };
   492→    }
   493→    if (controllerState === 'failure') {
   494→      return { status: 'failure', errorMessage: result.error || 'Execution failed' };
   495→    }
   496→    if (result.status === 'failed') {
   497→      return { status: 'failure', errorMessage: result.error };
   498→    }
   499→    if (result.status === 'timeout') {
   500→      return { status: 'timeout', errorMessage: 'Session timed out' };
   501→    }
   502→
   503→    return { status: 'success' };
   504→  }
   505→
   506→  /**
   507→   * Collect evidence for success criteria
   508→   */
   509→  private async verifyPhase(
   510→    useCase: UseCase,
   511→    execution: UseCaseExecution,
   512→    sessionLogPath: string
   513→  ): Promise<{ artifacts: EvidenceArtifact[]; allPassed: boolean }> {
   514→    if (useCase.successCriteria.length === 0) {
   515→      console.log('[Executor] No success criteria to verify');
   516→      return { artifacts: [], allPassed: true };
   517→    }
   518→
   519→    const collector = new EvidenceCollector();
   520→
   521→    try {
   522→      const result = await collector.collect(useCase.successCriteria, {
   523→        executionId: execution.id,
   524→        useCaseId: useCase.id,
   525→        evidenceRoot: this.options.evidenceRoot,
   526→        sessionLogPath,
   527→      });
   528→
   529→      // Convert criterion results to evidence artifacts
   530→      const artifacts: EvidenceArtifact[] = result.manifest.criteria.flatMap((criterion, index) =>
   531→        criterion.artifacts.map((artifact) => ({
   532→          type: artifact.type as 'screenshot' | 'response' | 'log-excerpt',
   533→          path: artifact.path,
   534→          criterionIndex: index,
   535→          timestamp: new Date(),
   536→          metadata: {},
   537→        }))
   538→      );
   539→
   540→      return {
   541→        artifacts,
   542→        allPassed: result.manifest.allPassed,
   543→      };
   544→    } catch (error) {
   545→      console.error('[Executor] Verification error:', error);
   546→      return { artifacts: [], allPassed: false };
   547→    }
   548→  }
   549→
   550→  /**
   551→   * Clean up resources created during execution
   552→   */
   553→  private async cleanupPhase(
   554→    useCase: UseCase,
   555→    execution: UseCaseExecution,
   556→    sessionLogPath: string
   557→  ): Promise<CleanupStatus> {
   558→    if (useCase.cleanupRequirements.length === 0) {
   559→      console.log('[Executor] No cleanup requirements defined');
   560→      return { status: 'complete', deleted: [], failed: [] };
   561→    }
   562→
   563→    const tracker = new ResourceTracker();
   564→
   565→    try {
   566→      // Parse session log for created resources
   567→      await tracker.collectFromSessionLog(sessionLogPath, useCase.cleanupRequirements);
   568→      const resources = tracker.getAll();
   569→
   570→      if (resources.length === 0) {
   571→        console.log('[Executor] No resources found to clean up');
   572→        return { status: 'complete', deleted: [], failed: [] };
   573→      }
   574→
   575→      console.log(`[Executor] Found ${resources.length} resources to clean up`);
   576→
   577→      // Use custom deletion invoker or default (no-op for now)
   578→      const deletionInvoker: DeletionInvoker =
   579→        this.options.deletionInvoker ??
   580→        (async (resource) => {
   581→          console.log(`[Executor] Would delete ${resource.type} ${resource.id} via ${resource.deletionTool}`);
   582→          // In production, this would invoke the actual MCP tool
   583→          return { success: true };
   584→        });
   585→
   586→      const executor = new CleanupExecutor(deletionInvoker);
   587→      return await executor.cleanup(resources, useCase.cleanupRequirements);
   588→    } catch (error) {
